import { Component, OnInit, OnDestroy } from '@angular/core';
import { Router } from '@angular/router';
import { Subject, Subscription, timer } from 'rxjs';
import { takeUntil, switchMap } from 'rxjs/operators';
import { ContestationService } from '../../services/contestation.service';
import {
  ContestationFilters,
  ContestationResponse,
  ContestationStatus,
  PageResponse
} from '../../models/contestation.model';

@Component({
  selector: 'app-contestation-list',
  templateUrl: './contestation-list.component.html'
})
export class ContestationListComponent implements OnInit, OnDestroy {
  private destroy$ = new Subject<void>();
  private refreshDestroy$ = new Subject<void>();

  pageData: PageResponse<ContestationResponse> | null = null;
  loading = false;
  errorMsg = '';

  filters: ContestationFilters = {
    page: 0,
    size: 10,
    status: '',
    contestationId: '',
    fromDate: '',
    toDate: ''
  };

  statusOptions: { label: string; value: ContestationStatus | '' }[] = [
    { label: 'Todos', value: '' },
    { label: 'Em Andamento', value: 'EM_ANDAMENTO' },
    { label: 'Sucesso', value: 'SUCESSO' },
    { label: 'Cancelado', value: 'CANCELADO' },
    { label: 'Callback Falha', value: 'CALLBACK_FALHA' }
  ];

  autoRefresh = false;

  constructor(
    private contestationService: ContestationService,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.loadContestations();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
    this.refreshDestroy$.next();
    this.refreshDestroy$.complete();
  }

  loadContestations(): void {
    this.loading = true;
    this.errorMsg = '';

    this.contestationService.listContestations(this.filters).subscribe({
      next: (data) => {
        this.pageData = data;
        this.loading = false;
      },
      error: (err) => {
        this.errorMsg = err.error?.message || 'Erro ao carregar contestações';
        this.loading = false;
      }
    });
  }

  applyFilters(): void {
    this.filters.page = 0;
    this.loadContestations();
  }

  clearFilters(): void {
    this.filters = {
      page: 0,
      size: 10,
      status: '',
      contestationId: '',
      fromDate: '',
      toDate: ''
    };
    this.loadContestations();
  }

  goToPage(page: number): void {
    this.filters.page = page;
    this.loadContestations();
  }

  viewDetail(requestId: string): void {
    this.router.navigate(['/contestations', requestId]);
  }

  getStatusClass(status: ContestationStatus): string {
    const map: Record<ContestationStatus, string> = {
      'EM_ANDAMENTO': 'badge-em-andamento',
      'SUCESSO': 'badge-sucesso',
      'CANCELADO': 'badge-cancelado',
      'CALLBACK_FALHA': 'badge-callback-falha'
    };
    return map[status] || '';
  }

  getStatusIcon(status: ContestationStatus): string {
    const icons: Record<ContestationStatus, string> = {
      'EM_ANDAMENTO': '⏳',
      'SUCESSO': '✅',
      'CANCELADO': '🚫',
      'CALLBACK_FALHA': '❌'
    };
    return icons[status] || '•';
  }

  get pages(): number[] {
    if (!this.pageData) return [];
    return Array.from({ length: this.pageData.paginacao.totalPaginas }, (_, i) => i);
  }

  toggleAutoRefresh(): void {
    this.autoRefresh = !this.autoRefresh;
    if (this.autoRefresh) {
      this.refreshDestroy$ = new Subject<void>();
      timer(5000, 5000)
        .pipe(
          takeUntil(this.refreshDestroy$),
          switchMap(() => this.contestationService.listContestations(this.filters))
        )
        .subscribe({
          next: (data) => { this.pageData = data; },
          error: () => {}
        });
    } else {
      this.refreshDestroy$.next();
    }
  }
}
<div class="page-content">
  <div class="d-flex justify-between align-center mb-2">
    <div class="page-title" style="margin-bottom:0">
      <span>📊</span> Contestações
      <span class="text-muted" *ngIf="pageData" style="font-size:14px;font-weight:400">
        ({{ pageData.pagination.totalElements }} registro(s))
      </span>
    </div>
    <div class="d-flex gap-2">
      <button
        class="btn btn-sm"
        [class.btn-primary]="autoRefresh"
        [class.btn-secondary]="!autoRefresh"
        (click)="toggleAutoRefresh()"
        title="Auto refresh a cada 5s">
        {{ autoRefresh ? '🔴 Stop Auto Refresh' : '🔄 Auto Refresh' }}
      </button>
      <button class="btn btn-sm btn-secondary" (click)="loadContestations()" [disabled]="loading">
        {{ loading ? '...' : '🔃 Atualizar' }}
      </button>
    </div>
  </div>

  <!-- Filtros -->
  <div class="filters-section">
    <div class="form-group" style="margin-bottom:0">
      <label>Status</label>
      <select class="form-control" [(ngModel)]="filters.status">
        <option *ngFor="let opt of statusOptions" [value]="opt.value">{{ opt.label }}</option>
      </select>
    </div>

    <div class="form-group" style="margin-bottom:0">
      <label>Contestation ID</label>
      <input type="text" class="form-control" [(ngModel)]="filters.contestationId" placeholder="CONT-..." />
    </div>

    <div class="form-group" style="margin-bottom:0">
      <label>De</label>
      <input type="datetime-local" class="form-control" [(ngModel)]="filters.fromDate" />
    </div>

    <div class="form-group" style="margin-bottom:0">
      <label>Até</label>
      <input type="datetime-local" class="form-control" [(ngModel)]="filters.toDate" />
    </div>

    <div class="form-group" style="margin-bottom:0">
      <label>Registros por página</label>
      <select class="form-control" [(ngModel)]="filters.size">
        <option [value]="5">5</option>
        <option [value]="10">10</option>
        <option [value]="25">25</option>
        <option [value]="50">50</option>
      </select>
    </div>

    <div style="display:flex;gap:8px;align-items:flex-end">
      <button class="btn btn-primary btn-sm" (click)="applyFilters()">🔍 Filtrar</button>
      <button class="btn btn-secondary btn-sm" (click)="clearFilters()">✖ Limpar</button>
    </div>
  </div>

  <!-- Erro -->
  <div *ngIf="errorMsg" class="alert alert-danger">⚠️ {{ errorMsg }}</div>

  <!-- Loading -->
  <div *ngIf="loading" class="text-center" style="padding:40px">
    <div class="spinner spinner-dark" style="width:32px;height:32px;margin:0 auto"></div>
    <p class="text-muted mt-1">Carregando...</p>
  </div>

  <!-- Tabela -->
  <div class="card" *ngIf="!loading">
    <div class="table-responsive">
      <table>
        <thead>
          <tr>
            <th>Status</th>
            <th>Request ID</th>
            <th>Contestation ID</th>
            <th>Recebido em</th>
            <th>Atualizado em</th>
            <th>Ações</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let item of pageData?.content">
            <td>
              <span class="badge" [ngClass]="getStatusClass(item.communicationStatus)">
                {{ getStatusIcon(item.communicationStatus) }} {{ item.communicationStatus }}
              </span>
            </td>
            <td>
              <span class="text-mono">{{ item.requestId | slice:0:8 }}...</span>
            </td>
            <td><span class="text-mono">{{ item.contestationId }}</span></td>
            <td>{{ item.receivedAt | date:'dd/MM/yy HH:mm:ss' }}</td>
            <td>{{ item.updatedAt | date:'dd/MM/yy HH:mm:ss' }}</td>
            <td>
              <button
                class="btn btn-sm btn-secondary"
                (click)="viewDetail(item.requestId)"
                title="Ver detalhes">
                🔍 Detalhe
              </button>
            </td>
          </tr>
        </tbody>
      </table>

      <!-- Empty state -->
      <div *ngIf="!pageData?.content?.length" class="empty-state">
        <div class="empty-icon">📭</div>
        <p>Nenhuma contestação encontrada.</p>
        <p class="text-muted">Tente ajustar os filtros ou criar uma nova contestação.</p>
      </div>
    </div>

    <!-- Paginação -->
    <div class="pagination" *ngIf="pageData && pageData.pagination.totalPages > 1">
      <button
        [disabled]="pageData.pagination.pageNumber === 0"
        (click)="goToPage(0)"
        title="Primeira página">
        «
      </button>
      <button
        [disabled]="pageData.pagination.pageNumber === 0"
        (click)="goToPage(pageData.pagination.pageNumber - 1)"
        title="Página anterior">
        ‹
      </button>

      <button
        *ngFor="let p of pages"
        [class.active]="p === pageData.pagination.pageNumber"
        (click)="goToPage(p)">
        {{ p + 1 }}
      </button>

      <button
        [disabled]="pageData.pagination.pageNumber === pageData.pagination.totalPages - 1"
        (click)="goToPage(pageData.pagination.pageNumber + 1)"
        title="Próxima página">
        ›
      </button>
      <button
        [disabled]="pageData.pagination.pageNumber === pageData.pagination.totalPages - 1"
        (click)="goToPage(pageData.pagination.totalPaginas - 1)"
        title="Última página">
        »
      </button>
    </div>

    <!-- Info paginação -->
    <div *ngIf="pageData" style="text-align:center;font-size:12px;color:#888;padding:8px 0">
      Página {{ pageData.pagination.pageNumber + 1 }} de {{ pageData.pagination.totalPaginas }}
      — {{ pageData.pagination.totalElements }} registro(s) total
    </div>
  </div>
</div>
